template <size_t N>
std::optional<int64_t> lookup_magic_array(uint64_t magic, uint64_t power, const MagicEntry (&arr)[N]) {
    MagicEntry target{magic, power, 0};
    auto it = std::lower_bound(arr, arr + N, target);
    if (it != arr + N && it->magic == magic && it->power == power) {
        return it->divisor;
    }
    return std::nullopt;
}

